#include <stdio.h>

int main(){
    int a,b,c;
    if(scanf("%d %d %d",&a,&b,&c)!=3) return 0;
    int ans = (b > a + c && b % 2 != 0) ? 1 : 0;
    printf("%d\n",ans);
    return 0;
}

